/// <reference path="../../typings/index.d.ts" />
import jibo = require('jibo');

/**
* View class created to test use of custom transitions
* @class PhotoView
* @extends module:jibo/face.View
*/
class FlashView extends jibo.rendering.gui.views.View
{
    public static log = null;
    /**
    * The default class identifier.
    * Generally used to register the class.
    * @name module:jibo/face.TransMenu#DEFAULT_TYPE
    * @type {String}
    * @private
    * @readOnly
    */
    public static get DEFAULT_TYPE():string {return 'FlashView';}

    private _whiteClip:jibo.rendering.gui.components.Clip;
    private _loaderClip:jibo.rendering.gui.components.Clip;

    /**
    * The Class type variant.
    * The MenuButton allows for type variants within it.
    * @overrides
    * @name module:jibo/face.TransMenu#_type
    * @type {String}
    * @protectedjibo sim /
    */
    protected _type:string = FlashView.DEFAULT_TYPE;

    //////////////////////// CONSTRUCTION ////////////////////////

    /**
     * Construct View
     */
    constructor () {
        super();
        // have custom eye transitions happen in all cases of transition to or from EyeView
        this.id = 'flashView';
        this.transitionStageOnly = true;
        this.closeOnSwipeDown = false;
        (<any>this)._category = jibo.face.views.CATEGORY_DISPLAY;
    }

    public flashWhite(done:Function):void{
        jibo.rendering.tween.TweenManager.play(
            this._whiteClip.display,
            {
                to: { alpha: 0 },
                duration: 500,
                ease: 'sineOut'
            },
            () => {
                if(done){
                    done();
                }
            }
        );
    }

    public startLoader():void{
        // stop loder animation
        this._loaderClip.movieClip.play();
    }

    public applyData():void {

        // add loader animation
        this._loaderClip = new jibo.rendering.gui.components.Clip();
        // TODO :: Provide easier accesss to loader clip, allowing GLOBAL_CACHE to remain undoced
        this._loaderClip.addAssetDescriptorObject(
            {
                id: 'loader',
                type: 'timeline',
                src: 'core://resources/buttons/loader.js'//,
                //cache: 'global-gui'//jibo.rendering.gui.ViewManager.GLOBAL_CACHE
            }
        );
        this._loaderClip.setTargetPosition(jibo.face.width/2, jibo.face.height/2);
        super.addComponent(this._loaderClip, 'loader');

        super.applyData();
    }

    public ready():void {
        // create clip for white flash
        this.addWhite();
        // stop loder animation
        this._loaderClip.movieClip.stop();

        super.ready();
    }

    private addWhite() {
        // create white graphic the size of the screen
        let graphics:PIXI.Graphics = new PIXI.Graphics();
        graphics.beginFill(0xFFFFFF);
        graphics.drawRect(0, 0, jibo.face.width, jibo.face.height);
        graphics.endFill();

        this._whiteClip = <jibo.rendering.gui.components.Clip>super.addComponent(
            jibo.rendering.gui.components.Clip.createFromDisplayObject(graphics, this.stage),
            'whiteClip'
        );
    }
}

export default FlashView;
