/// <reference path="../typings/index.d.ts" />
import {BeSkill, Options} from '@be/be-framework';
import jibo = require('jibo');
import CameraView from './views/CameraView';
import FlashView from './views/FlashView';
import PhotoView from './views/PhotoView';
import Analytics from './Analytics';
import FaceSearcher from './photo/FaceSearcher';
import FrameHelper from './photo/FrameHelper';

let mainFlow: any = require('./flows/main');
const FaceFinder = require('./photo/FaceFinder');

const DANCE_RULE = 'tutorial/dance';
const PHOTO_RULE = 'tutorial/take_photo';

class Tutorial extends BeSkill {

    public flow: jibo.flow.FlowExecutor = null;
    public endOfListen: boolean = false;

    private _fromOOBE: boolean = false;
    private _photo: any;
    private _clipId: string;
    private _onHeadTouch: Function;
    private _onHJ: Function;
    private _onHJCommand: Function;
    private _headTimer: any;
    private _hjTimer: any;
    private _pmHandle: jibo.expression.AttentionHandle;
    private _hjModeToken: jibo.jetstream.HotwordModeToken;
    private _blockingHeadTouch: boolean = false;
    private _tracker:Analytics = null;
    private WAIT_TIME: number = 6000;

    private SECONDS_TO_HOLD_TOUCH:number = 1;

    private _onHjOnlyCommand: Function;
    private _onNoMatchCommand: Function;
    private _onHjHeard: Function;

    private _assetTokens: any[];


    /**
     * Template skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?: Options) {
        super(assetPack);
        // bind methods
        this.onHJHeard = this.onHJHeard.bind(this);
        this.blockSkillSwitch = this.blockSkillSwitch.bind(this);
        this.blockHeadTouchOn = this.blockHeadTouchOn.bind(this);
        this.blockHeadTouchOff = this.blockHeadTouchOff.bind(this);
        this.blockHeadTouch = this.blockHeadTouch.bind(this);
        this.onHJOnly = this.onHJOnly.bind(this);
        this.onNoGlobalMatch = this.onNoGlobalMatch.bind(this);
        this.handleHJ = this.handleHJ.bind(this);
        // assign logs
        FaceSearcher.log = this.log.createChild('FaceSearcher');
        FrameHelper.log = this.log.createChild('FrameHelper');
        FaceFinder.log = this.log.createChild('FaceFinder');
        CameraView.log = this.log.createChild('CameraView');
        FlashView.log = this.log.createChild('FlashView');
        PhotoView.log = this.log.createChild('PhotoView');
    }

    public preload(done: (err?: any) => void): void {
        done();
    }

    /**
     * Start the skill
     * @method open
     */
    public open(result?: any, refresh?: boolean, previousSkillName?: string, previousSkillOptions?: any): void {
        if (refresh) {
            this.log.debug('open () refresh');

            if (this._fromOOBE){ // on first connection, don't allow restart
                // allow MIM to be unblocked
                jibo.globalEvents.shared.nonInterruptingGlobal.emit();
            } else {
                // clean up, then call open again
                this.cleanup(this.open.bind(this, result, false, previousSkillName, previousSkillOptions));
            }
        }
        else {
            // NOTE :: Should be 0, can set to when debugging to skip to specific tutorial section
            const start_step:number = 0;
            // register view classes
            jibo.face.views.creator.registerClass(CameraView);
            jibo.face.views.creator.registerClass(FlashView);
            jibo.face.views.creator.registerClass(PhotoView);
            // load sfx, don't need to wait, they should be loaded by the time we need them
            const load = jibo.loader.load([
                'audio/camera-shutter.m4a',
                'audio/screen-swipedown.m4a',
                'audio/screen-tap.m4a',
            ], {
                //cache all audio in the active cache, which is the skill's cache courtesy of Be
                cacheAll: jibo.loader.activeCache
            });
            this._assetTokens = load.tokens;
            // establish eye view
            jibo.face.views.forceEyeView();
            // set from OOBE flag
            this._fromOOBE = previousSkillName === '@be/first-contact';
            this.log.debug('open() previousSkillName: ' + previousSkillName);
            // If coming from First Contact do not allow interruption of Tutorial
            if (this._fromOOBE) {
                this.log.debug('open() coming from First Contact, setting OOBE flag to true');
                // block interrupt via head touch
                jibo.globalEvents.touchStop.on(this.blockHeadTouch);
                this._blockingHeadTouch = false;
                // block hey jibo
                this.disableHJ();

                // block skill launch
                this._isInterruptible = false;
                jibo.globalEvents.skillRelaunch.on(this.blockSkillSwitch);
            } else {
                // reset blocking flags
                this._blockingHeadTouch = false;
                // can interrupt
                this._isInterruptible = true;
            }

            // instantiate tracker, if tracker is not null then we are refreshing skill
            let launchSource:'from_fc'|'menu'|'speech';
            if(this._fromOOBE){
                launchSource = 'from_fc';
            }else{
                launchSource = (previousSkillName === '@be/main-menu') ? 'menu' : 'speech';
            }
            if(!this._tracker){
                this._tracker = new Analytics(this);
            }
            this._tracker.reset(launchSource);
            this._tracker.started();

            const options = {
                assetPack: this.assetPack,
                enableLogging: true,
                blackboard: {
                    skill: this,
                    step: start_step,
                    waitTime: this.WAIT_TIME,
                    version: 'mainMenu',
                    oobe: this._fromOOBE,
                    faceFinder: new FaceFinder(),
                    tracker: this._tracker,
                    log: this.log,
                    lightRing: this.setLightRing,
                    headRatio: .56
                }
            };
            this.flow = jibo.flow.run(mainFlow, options, (err, status) => {
                this.log.debug('flow ended');
                if (status !== jibo.bt.Status.INTERRUPTED) {
                    // tracking skill completed naturally
                    this._tracker.completed(true);
                    this._isInterruptible = true;
                    jibo.globalEvents.skillRelaunch.removeListener(this.blockSkillSwitch);
                    if ((this.flow as any).context.result.transition === 'enrollment') {
                        this.log.info('redirecting to enrollment');
                        this.redirect('@be/introductions', {nlu:{entities:{domain:'introductions'}, intent:'enrollment'}});
                    }else{
                        this.exit();
                    }
                }
                else{
                    // tracking that skill did not completed nnatural due to interruption
                    this._tracker.completed(false);
                }
            });
        }

    }

    public setLightRing(turnOn:boolean):void{
        if(turnOn){
            jibo.embodied.listen.enterActiveMode(jibo.embodied.listen.ActiveListenMode.UI);
        }else{
            jibo.embodied.listen.exitActiveMode();
        }
    }

    public async setMode(mode: jibo.expression.AttentionMode): Promise<jibo.expression.AttentionHandle> {
        this._pmHandle = await jibo.expression.pushAttentionMode(mode);
        return this._pmHandle;
    }

    public async releaseMode(): Promise<void> {
        if (this._pmHandle) {
            await this._pmHandle.release();
            this._pmHandle = null;
        }
    }

    public hasLoopers(done:Function):void {
        jibo.kb.loop.loadLoop((err, userNodes)=> {
            if (err || !userNodes) {
                done(false);
                return;
            }
            for(let looper of userNodes) {
                if (!looper.isJibo) {
                   done(true);
                   return;
                }
            }
            done(false);
        });
    }

    //////////// HELPER METHODS ////////////

    /**
     * Turn embodied listen on or off
     */
    public setEngaged(bool: boolean): void {
        jibo.embodied.listen.demoEngaged(bool);
    }

    /**
     * Store photo data
     * @method storePhoto
     */
    public storePhoto(photo: any) {
        this._photo = photo;
    }

    /**
     * Get stored photo data
     * @method getPhoto
     */
    public getPhoto(): any {
        return this._photo;
    }

    ///////////////////// HJ LISTEN /////////////////////

    public async waitForHJ(done: Function) {
        this._onHJ = done;
        
        jibo.jetstream.events.hjHeard.on(this.onHJHeard);
        await this.releaseHJToken();
        this._hjModeToken = jibo.jetstream.setHotwordMode(jibo.jetstream.types.HotwordListenMode.HJ_Only);
    }

    public async cleanUpHJ(): Promise<void> {
        this._onHJ = null;
        jibo.jetstream.events.hjHeard.off(this.onHJHeard);
        await this.releaseHJToken();
        if (this._fromOOBE) {
            await this.disableHJ();
        }
    }

    ///////////////////// HJ SKILL LAUNCH /////////////////////

    // clear stack and open view showing HJ command text, no need to wait on this to finish before starting listen
    public showCommandView(type: string, done?: Function): void {
        let viewPath: string = type === 'dance' ? 'assets/views/hey-jibo-dance.json' : 'assets/views/hey-jibo-take-photo.json';
        jibo.face.views.changeView(
            {
                removeAll: true,
                addView: viewPath
            },
            () => { done(); },
            () => {
                this.log.warn('showCommandView() failed to create view ' + type);
                done();
            }
        );
    }

    public async waitForHJCommand(command: 'dance'|'photo', done: Function): Promise<void> {
        this._onHJCommand = done;
        
        await this.releaseHJToken();
        //because we are disabling all other global rules, we re-enable normal global commands to
        //allow for the normal commands to be used (still blocking skill switches if from OOBE)
        const rules = ['globals/global_commands_launch', command === 'dance' ? DANCE_RULE : PHOTO_RULE];
        this._hjModeToken = jibo.jetstream.setHotwordMode(
            jibo.jetstream.types.HotwordListenMode.Custom_NLU_Only,
            rules
        );
        this._hjModeToken.match.on((match) => {
            const targetIntent = command === 'dance' ? 'dance' : /photo/i;
            if (match.result.nlu && match.result.nlu.intent.match(targetIntent)) {
                if (this._onHJCommand) {
                    this._onHJCommand();
                }
                return;
            }
            //if it triggered our rule but we didn't match it, then we should treat it as a no match
            if (!this._fromOOBE) {
                this.onNoGlobalMatch();
            }
        });
    }

    public async cleanUpHJCommand(): Promise<void> {
        this._onHJCommand = null;
        await this.releaseHJToken();
        if (this._fromOOBE) {
            await this.disableHJ();
        }
    }

    ///////////////////// HJ HANDLE /////////////////////

    public cleanUpHjHandle(): void {
        this._onHjOnlyCommand = null;
        jibo.globalEvents.shared.hjOnly.off(this.onHJOnly);
        this._onHjHeard = null;
        jibo.jetstream.events.hjHeard.off(this.onHJHeard);
        this._onNoMatchCommand = null;
        jibo.globalEvents.shared.noGlobalMatch.off(this.onNoGlobalMatch);
        clearTimeout(this._hjTimer);
        this._hjTimer = null;
    }

    public handleHJ(done: Function): void {
        this.cleanUpHjHandle();
        this._hjTimer = setTimeout( () => {
            this.cleanUpHjHandle();
            done('wait');
        }, this.WAIT_TIME);

        this.waitForHjHeard( ()=> {
            clearTimeout(this._hjTimer);
        });

        this.waitForHjOnly( ()=> {
            this.cleanUpHjHandle();
            done('hjOnly');
        });

        this.waitForNoMatch( ()=> {
            this.cleanUpHjHandle();
            done('noMatch');
        });

    }

    ///////////////////// HEAD TOUCH /////////////////////

    public waitForHeadTouch(done: Function) {
        // remove the global block so we can get incremental touch events from system (need for OOBE which is blocking global touch to stop)
        this.interruptHeadTouch(true);
        this._onHeadTouch = done;
    }

    public interruptHeadTouch(block: boolean): void {
        if (this._blockingHeadTouch !== block) {
            this._blockingHeadTouch = block;
            if (block) {
                if(this._fromOOBE){
                    jibo.globalEvents.touchStop.removeListener(this.blockHeadTouch);
                }
                else{
                    // block skill relaunch, but listen for attempt so we can unblock MIM
                    this._isInterruptible = false;
                    jibo.globalEvents.skillRelaunch.on(this.blockSkillSwitch);
                }
                // listen for head touch events
                jibo.system.events.touchOn.on(this.blockHeadTouchOn);
                jibo.system.events.touchOff.on(this.blockHeadTouchOff);
                //jibo.globalEvents.voiceStop.on(this.blockHeadTouchOn);  // NOTE : only teaching head touch
            } else {
                jibo.system.events.touchOn.removeListener(this.blockHeadTouchOn);
                jibo.system.events.touchOff.removeListener(this.blockHeadTouchOff);
                //jibo.globalEvents.voiceStop.removeListener(this.blockHeadTouchOn);  // NOTE : only teaching head touch
                if(this._fromOOBE){
                    jibo.globalEvents.touchStop.on(this.blockHeadTouch);
                }else{
                    // unblock skill relaunch
                    this._isInterruptible = true;
                    jibo.globalEvents.skillRelaunch.removeListener(this.blockSkillSwitch);
                }
            }
        }
    }

    public cleanUpHeadTouch() {
        // add back global block once we're done (need for OOBE which is blocking global touch to stop)
        this._onHeadTouch = null;
    }

    ///////////////////// GESTURES /////////////////////

    public waitForGesture(done: Function, id: string) {
        switch (id) {
            case 'tap': {
                jibo.face.views.currentView.addAction('callback',
                    {
                        callback: () => {
                            if( jibo.sound.exists('screen-tap') ) {
                                jibo.sound.play('screen-tap');
                            }
                            jibo.face.views.currentView.removeActionsByType('callback');
                            done(true);
                        }
                    }
                );
                break;
            }
            case 'pan': {
                let onPaged = (data) => {
                    jibo.face.views.currentView.removeListener('paged', onPaged);
                    done(true);
                };
                // add listener to paged
                jibo.face.views.currentView.on('paged', onPaged);
                break;
            }
            case 'swipe': {
                // add back close on swipe down
                this.addSwipeClose();
                let onClosed = (data) => {
                    if( jibo.sound.exists('screen-swipedown') ) {
                        jibo.sound.play('screen-swipedown');
                    }
                    done(true);
                };
                jibo.face.views.currentView.on(jibo.face.views.CLOSED, onClosed);
                break;
            }
            default: {
                console.warn('Tutorial :: waitForGesture : Invalid gesture id');
                break;
            }
        }
    }

    public cleanUpGesture(id: string) {
        switch (id) {
            case 'tap': {
                jibo.face.views.currentView.removeActionsByType('callback');
                break;
            }
            case 'pan': {
                // TODO :: Not sure if anyone else may be listening to this at the view level?
                jibo.face.views.currentView.removeAllListeners('paged');
                break;
            }
            case 'swipe': {
                // no clean up required
                break;
            }
            default: {
                this.log.warn('cleanUpGesture() invalid gesture id: ' + id);
                break;
            }
        }
    }

    public addSwipeClose() {
        // add back close event and close view
        jibo.face.views.currentView.addAction(
            jibo.face.views.ActionData.EVENT,
            {event:jibo.face.views.BACK},
            false,
            false,
            jibo.face.views.SWIPE
        );
        jibo.face.views.currentView.addAction(
            jibo.face.views.ActionData.CLOSE_VIEW,
            null,
            false,
            false,
            jibo.face.views.SWIPE
        );
    }

    public playClip(clipId: string, done?: Function, withinView?: string): void {
        let view: jibo.face.views.View = jibo.face.views.currentView;
        let asset: any = view.assets[clipId];
        let assetDescriptor: any = {
            id: clipId,
            type: 'timeline',
            src: 'assets/timelines/' + clipId + '/' + clipId + '.js',
            instance: true
        };
        if (withinView && withinView !== view.id) {
          return;
        }
        // if asset has been loaded by view create and play CLip
        if (asset) {
            // create Clip & add to current view
            let config: any = { id: clipId, assets: [assetDescriptor] };
            let clip: jibo.face.views.Clip = jibo.rendering.gui.components.Clip.createFromConfig(config);
            view.addComponent(clip, clipId);
            clip.createDisplay(view.stage, view.assets);

            // tween in alpha and play clip
            clip.movieClip.gotoAndStop(0);
            jibo.rendering.tween.TweenManager.play(
                clip.display,
                {
                    to: { 'alpha': 1 },
                    from: { 'alpha': 0 },
                    duration: 500,
                    ease: 'sineOut'
                },
                () => {
                    clip.movieClip.gotoAndPlay(0);
                }
            );
            if (done) {
                done();
            }
        }
        else {
            // if asset has been not been loaded then load asset and recurse
            view.addAssets(assetDescriptor, (err) => {
                if(err) {
                    this.log.error('failed to load asset, exiting skill');
                    this.exit();
                }
                else {
                    this.playClip(clipId, done);
                }
            });
        }
    }

    public stopClip(clipId: string, done?: Function): void {
        let view: jibo.face.views.View = jibo.face.views.currentView;
        let clip: jibo.face.views.Clip = <jibo.face.views.Clip>view.getComponentById(clipId);
        if (clip) {
            jibo.rendering.tween.TweenManager.play(
                clip.display,
                {
                    to: { 'alpha': 0 },
                    duration: 200,
                    ease: 'sineIn'
                },
                () => {
                    clip.movieClip.stop();
                    if (done) {
                        done();
                    }

                }
            );
        } else {
            this.log.warn('stopClip() current view did not have clip id: ' + clipId);
            if (done) {
                done();
            }
        }

    }

    //////////// CLOSURE METHODS ////////////

    /**
     * Stop and unload the skill
     * @method close
     */
    public close(done: () => void): void {
        // unload sounds
        jibo.loader.unload(this._assetTokens);
        this._assetTokens = null;
        // unregister view classes
        jibo.face.views.creator.unregisterClass('CameraView');
        jibo.face.views.creator.unregisterClass('FlashView');
        jibo.face.views.creator.unregisterClass('PhotoView');

        this.cleanup(done);
    }

    ////////////// CLOSE ///////////////

    /**
     * Clean up flows
     * @method cleanup
     */
    private cleanup(done: () => void): void {
        const cleanup:Promise<any>[] = [];
        //if flow exists, make sure we stop it before starting to run other cleanup code
        if (this.flow) {
            cleanup.push(
                //stop & destroy the main flow
                this.flow.stop()
                    .catch((err) => {
                        this.log.debug('Error when stopping flow: ', err);
                    })
                    .then(() => {
                        this.flow.destroy();
                        this.flow = null;
                    })
            );
        }
        cleanup.push(
            // release any modes handles
            this.releaseMode(),
            this.releaseHJToken(),

            // disable viewfinder (in case we were interrupted while it was open)
            this.disableViewFinder()
                .catch((err) => {
                    this.log.debug('cleanup() setViewfinder disable error: ', err);
                }),

            //clean up views
            this.cleanupViews()
                .catch((err) => {
                    this.log.debug('Eror when closing views: ', err);
                })
        );
        
        Promise.all(cleanup).then(() => {
            this.cleanupHandlers();
            done();
        });
    }

    private cleanupHandlers(): void {

        // clear forced engage
        jibo.embodied.listen.demoEngaged(false);

        // remove listeners
        jibo.jetstream.events.hjHeard.removeListener(this.onHJHeard);
        jibo.globalEvents.shared.hjOnly.removeListener(this.onHJOnly);
        jibo.globalEvents.skillRelaunch.removeListener(this.blockSkillSwitch);
        jibo.system.events.touchOn.removeListener(this.blockHeadTouchOn);
        jibo.system.events.touchOff.removeListener(this.blockHeadTouchOff);
        jibo.globalEvents.touchStop.removeListener(this.blockHeadTouch);

        // clear handlers
        this._onHJ = null;
        this._onHJCommand = null;
        this._onHeadTouch = null;

        // clear stored photo data
        this._photo = null;

        // clear flags
        this._blockingHeadTouch = false;

        // clear head-touch timer out and listeners
        if (this._headTimer) {
            clearTimeout(this._headTimer);
            this._headTimer = null;
        }
        // clear the HJ timer out
        if (this._hjTimer) {
            clearTimeout(this._hjTimer);
            this._hjTimer = null;
        }
    }

    /**
     * Make sure view finder is disabled.
     */
    private disableViewFinder(): Promise<void> {
        return new Promise<void>((resolve) => {
            jibo.media.setViewfinder(
                {enable: false},
                (error)=> {
                    if (error) {
                        this.log.error('cleanup() setViewfinder disable error: ',error);
                    }
                    resolve();
                }
            );
        });
    }

    /**
     * Clean up views.
     */
    private cleanupViews(): Promise<void> {
        // make sure tap component is removed from eye layer in case skill is closed at that point
        let view = jibo.face.views.currentView;
        if(view && view.category === jibo.face.views.CATEGORY_EYE) {
            const tapComponent:jibo.face.views.Clip = <jibo.face.views.Clip>view.getComponentById('tap');
            if (tapComponent) {
                view.removeComponent(tapComponent);
                tapComponent.emptyDisplay();
                tapComponent.destroy();
                view.removeAssets(view.assetManifest);
            }
        }

        return new Promise<void>((resolve) => {
            jibo.face.views.viewStackCleanup()
              .then(()=> {
                  resolve();
              })
              .catch(()=> {
                  this.log.debug('cleanupViews() failed to remove all views, calling done anyway');
                  resolve();
              });
        });
    }

    ////////////// HANDLERS ///////////////

    /**
     * Handler for HJ, both for listening for just HJ and listening for HJ + a command
     * @method onHJHeard
     */
    private onHJHeard() {
        if (this._onHJ) {
            this._onHJ('true');
            this._onHJ = null;
        } else if (this._onHjHeard) {
            this._onHjHeard();
            this._onHjHeard = null;
        }
        // allow MIM to be unblocked
        //jibo.globalEvents.shared.nonInterruptingGlobal.emit();
    }

    private onNoGlobalMatch() {
        if (this._onNoMatchCommand) {
            this._onNoMatchCommand();
            this._onNoMatchCommand = null;
        }
    }

    private onHJOnly() {
        if (this._onHjOnlyCommand) {
            this._onHjOnlyCommand();
            this._onHjOnlyCommand = null;
        }
    }

    private waitForNoMatch(done: Function): void {
        this._onNoMatchCommand = done;
        jibo.globalEvents.shared.noGlobalMatch.on(this.onNoGlobalMatch);
    }

    private waitForHjOnly(done: Function): void {
        this._onHjOnlyCommand = done;
        jibo.globalEvents.shared.hjOnly.on(this.onHJOnly);
    }

    private waitForHjHeard(done: Function): void {
        this._onHjHeard = done;
        jibo.jetstream.events.hjHeard.on(this.onHJHeard);
    }

    /**
     * Handler for Skill Relaunch
     * @method handleHeadTouch
     */
    private blockSkillSwitch(data) {
        let skillName: string;
        let input: string;
        if (data && data.nlu) {
            skillName = data.nlu.entities.skill;
            input = data.asr.text;
            this.log.info('blockSkillSwitch() received HJ Command for skill ${skillName} with input ${input}');
        }

        if (this._onHJCommand) {
            this._onHJCommand(skillName, input);
            this._onHJCommand = null;
        }
        // allow MIM to be unblocked
        jibo.globalEvents.shared.nonInterruptingGlobal.emit();
    }

    /**
     * Handler for Head Touch On
     * @method handleHeadTouch
     */
    private blockHeadTouchOn() {
        if (this._onHeadTouch) {
            // start timer
            this._headTimer = setTimeout(
                ()=> {
                    if(this._onHeadTouch){
                        this._onHeadTouch('true');
                        this._onHeadTouch = null;
                    }
                },
                this.SECONDS_TO_HOLD_TOUCH * 1000
            );
        }
    }

    private blockHeadTouchOff() {
        // if this is not the OOBE, and it's not the headTouch part of the
        // tutorial, stop when the head is touched
        if (!this._fromOOBE && !this._onHeadTouch){
            this.redirect("@be/idle", {});
        }

        if (this._headTimer) {
            clearTimeout(this._headTimer);
            this._headTimer = null;
        }
    }

    /**
     * Handler for Head Touch Off, stop and clear timer that is waiting for headTouch pass a certain duration
     * @method handleHeadTouch
     */
    private blockHeadTouch() {
        // do nothing, we just need a handler to block head touch
    }
    
    /**
     * Blocks HJ from being listened for, so that you can't interrupt or exit the post OOBE tutorial
     */
    private async disableHJ() {
        if (this._hjModeToken) {
            return;
        }
        this._hjModeToken = jibo.jetstream.setHotwordMode(jibo.jetstream.types.HotwordListenMode.Disabled);
        await this._hjModeToken.activated;
    }
    
    private async releaseHJToken() {
        if (this._hjModeToken) {
            const token = this._hjModeToken;
            this._hjModeToken = null;
            return token.release();
        }
    }
}

module.exports = Tutorial;
