/// <reference path="../../typings/index.d.ts" />
import jibo = require('jibo');
import THREE = require('@jibo/three');
import FaceScore from './FaceScore';
import FaceSearcher from './FaceSearcher';
import {BeSkill} from '@be/be-framework';
import FrameHelper from './FrameHelper';
const GoalFinishedStatus = jibo.action.types.GoalFinishedStatus;

/**
 * Contains methods to assist in find faces and centering them for a photo
 */
class FaceFinder {

    public static log = null;

    // not currently used
    public safeZone = {left:230, right:1115, top:100, bottom:590};//guideline for how much of camera 0 image is visible in camera 1

    // best score, derived from motion data
    private _bestScore:FaceScore;

    // class that manages searching via Attractable mode
    private _faceSearcher:FaceSearcher;

    // score that requires at least one face track with a confidence above 0
    public highScore:FaceScore;
    // score that requires at least one face track and no confidence
    public mediumScore:FaceScore;
    // score that requires at least one face detect with a confidence above 0
    public lowScore:FaceScore;

    // manage search results
    private _searchResult:any;
    private _awaitingResult:boolean;
    private _resultCallback:Function;

    public get faceSearcher():FaceSearcher{
        return this._faceSearcher;
    }

    constructor() {
        this.onSearchResult = this.onSearchResult.bind(this);

        this._faceSearcher = new FaceSearcher();
        // set score values
        this.highScore = new FaceScore();
        this.highScore.peopleTotal = 1;
        this.highScore.peopleConfidenceTotal = .2;
        this.highScore.generateHeuristic();
        this.mediumScore = new FaceScore();
        this.mediumScore.peopleTotal = 1;
        this.mediumScore.peopleConfidenceTotal = 0;
        this.mediumScore.generateHeuristic();
        this.lowScore = new FaceScore();
        this.lowScore.faceDetectTotal = 1;
        this.lowScore.faceDetectConfidence = .2;
        this.lowScore.generateHeuristic();
    }

    public destroy() {
        // make sure any ongoing search is deactivated
        this.stopSearch();
    }

    public reset(done):void {
        this._searchResult = null;
        this._awaitingResult = false;
        this._resultCallback = null;
    }

    /**
     * Reset search values
     */
    public resetSearch(done?:Function):void {
        FaceFinder.log.info('FaceFinder.resetSearch()');
        this._searchResult = null;
        this._awaitingResult = true;
        this._resultCallback = null;
        this.checkSearch(done);
    }

    /**
     * Check for results of current search.
     */
    public checkSearch(done:Function):void {
        if(done){
            if(this._awaitingResult){
                FaceFinder.log.info('FaceFinder.checkSearch() is awaiting results');
                // stil awaiting results, trigger callback when results are ready
                if(this._resultCallback){
                    FaceFinder.log.info('FaceFinder.checkSearch() overiding previous callback: '+this._resultCallback+' with: '+done);
                }
                this._resultCallback = done;
            }
            else{
                // return results from latest search
                FaceFinder.log.info('FaceFinder.checkSearch() results are available: '+this._searchResult);
                done(this._searchResult);
            }
        }
    }

    /**
     * Check results are ready, or if we are still waiting for them.
     */
    public get isAwaitingResults():boolean {
        return this._awaitingResult;
    }

    /**
    * Called when most recent search results are returned
    */
    public onSearchResult(result:any):void {
        FaceFinder.log.info('onSearchResult() search result: ' + result);
        this._awaitingResult = false;
        this._searchResult = result;
        if(this._resultCallback){
            this._resultCallback(result);
            this._resultCallback = null;
        }
    }

    /////////////////// FACE FIND APPROACHES ///////////////////

    /**
     * Instant check to see if there are faces found in current motion data.
     * Sets search result value.
     * Default score just requires a person entity(track) with a reasonable confidence.
     */
    public checkForFaces(score:FaceScore = this.highScore):boolean {
        this._awaitingResult = false;
        this._searchResult = score.checkForEqualBetter(new FaceScore(jibo.lps.motionData));
        return this._searchResult;
    }

    /**
     * Look for faces at current position, default score just requires a single face detect
     */
    public detectForFaces(done?:Function, score:FaceScore = this.lowScore):void {
        this.resetSearch(done);
        // force lps to think harder if there is face, limit of max 2 faces
        jibo.lps.demandDetect(
            0,
            false,
            (err) => {
                if(err) {
                    FaceFinder.log.info('FaceFinder.detectForFaces() encountered error from jibo.lps.demandDetect'+err);
                    this.onSearchResult(false);
                }
                else {
                    FaceFinder.log.info('FaceFinder.detectForFaces() completed');
                    this.onSearchResult(score.checkForEqualBetter(new FaceScore(jibo.lps.motionData)));
                }
            }
        );
    }

    /**
     * Use Actions too search for faces.  Position to HJ locations and look sdown at first HJ location.
     */
    public searchForFaces(done?:Function):void {
        this.resetSearch(done);
        // assuming we have failed to find faces at crrent position
        jibo.action.addFindPersonGoal().events.finished.waitFor()
        .then(status => {
            if (status === GoalFinishedStatus.SUCCEEDED) {
                this.onSearchResult(true);
            } else {
                this.onSearchResult(false);
            }
        });
    }

    /**
     * Start or stop a search for faces.
     */
    public startSearch(done?:Function, minScore?:FaceScore, duration:number = 0) {
        FaceFinder.log.info('FaceFinder.startSearch() minScore',minScore,' duration',duration);
        // reset the search result
        this.resetSearch(done);
        // actively check for faces
        this._faceSearcher.search(this.onSearchResult, minScore, duration);
    }

    public checkBest(minScore:FaceScore = this.lowScore):boolean {
        // actively check for faces
        return this._faceSearcher.checkAgainstBest(minScore);
    }

    public stopSearch(clearCallback:boolean = true) {
        this._faceSearcher.stopSearch(clearCallback);
    }

    /////////////////// FRAME FOR FACES ///////////////////

    /**
     * Get center position using all faces return from a full frame detection.
     * @param done
     * @param cameraTracking - id (0 or 1) of camera to use for getFaces (if used)
     * @param cameraPhoto - id (0 or 1) of camera that will be used to take the photo (need this info for framing correct FOV)
     * @param headHeightRatio - where to put head in frame 1 means at top, 0 at bottom, 0.5 in the middle
     * @param fovSafeRegion - fraction of total frame where faces are allowed.  1.0 means anywhere, 0.9 means only the middle 90%.
     */
    public findCenterFromFrame(done?:Function, cameraTracking:number = 0, cameraPhoto:number = 0, headHeightRatio:number = 0.5, fovSafeRegion:number = 0.9) {
        // reset the search
        this.resetSearch(done);

        FaceFinder.log.info('FaceFinder.findCenterFromFrame() Starting a getFaces request to LPS');
        jibo.lps.getFaces(
            cameraTracking,
            (err?:string | Error, result?:any) => {
                FaceFinder.log.info("FaceFinder.findCenterFromFrame() got a getFaces result"+(err?(" ERR:"+err):""));
                if(result && result.details && result.details.length) {
                    try {
                        FaceFinder.log.info('FaceFinder.findCenterFromFrame() getFaces found '+result.details.length+' faces');

                        // get targets from results of jibo.lps.getFaces
                        let targetPositions = [];
                        let allDetails = result.details;
                        for (let i = 0; i < allDetails.length; i++) {
                            let aDetail = allDetails[i];
                            let origin = new THREE.Vector3().copy(aDetail.ray_origin);
                            let direction = new THREE.Vector3().copy(aDetail.ray_dir);
                            let distance = aDetail.range;
                            let position = origin.add(direction.setLength(distance));
                            targetPositions.push(position);
                        }
                        // return look at coordinates
                        let lookAt = this.getCenterFromTargets(targetPositions, cameraTracking, cameraPhoto, headHeightRatio, fovSafeRegion);
                        this.onSearchResult(lookAt);

                    }catch(err){
                        FaceFinder.log.warn('FaceFinder.findCenterFromFrame() got error computing lookat:'+err);
                        this.onSearchResult(null);
                    }

                }else{
                    FaceFinder.log.info('FaceFinder.findCenterFromFrame() getFaces found NO faces');
                    this.onSearchResult(null);
                }
            },
            'faces',
            false
        );
    }

    /**
     * Get center position using provided targets.
     * @param THREE.Vector3[] - array of targets
     * @param cameraTracking - id (0 or 1) of camera to use for getFaces (if used)
     * @param cameraPhoto - id (0 or 1) of camera that will be used to take the photo (need this info for framing correct FOV)
     * @param headHeightRatio - where to put head in frame 1 means at top, 0 at bottom, 0.5 in the middle
     * @param fovSafeRegion - fraction of total frame where faces are allowed.  1.0 means anywhere, 0.9 means only the middle 90%.
     * @return any - center position calculatedf from targets and camera
     */
    public getCenterFromTargets(targetPositions:THREE.Vector3[], cameraTracking:number = 0, cameraPhoto:number = 0,
                                headHeightRatio:number = 0.5, fovSafeRegion:number = 0.9):THREE.Vector3 {
        // must send targets
        if(!targetPositions || targetPositions.length === 0){
            return null;
        }

        try {
            //position of camera:
            // [meters robot-left of face center along face plane, meters above LCD center along face plane]
            let cameraPosInFaceXY:number[];
            if(cameraPhoto === 0){
                cameraPosInFaceXY = [-0.041, 0.058];
            }else if(cameraPhoto === 1){
                cameraPosInFaceXY = [0.041, 0.058];
            }else{
                FaceFinder.log.warn('FaceFinder.getCenterFromTargets() unknown camera id:'+cameraPhoto+', using no offset');
                cameraPosInFaceXY = [0,0];
            }

            let features = jibo.expression.features;
            let headFeature = features.head;
            let currentDirection = new THREE.Vector3().copy(headFeature.direction);
            let currentOrigin = new THREE.Vector3().copy(headFeature.position);

            let FoV = jibo.lps.motionData.cameras[cameraPhoto].fov;
            let fovX = FoV.x * fovSafeRegion;
            let fovY = FoV.y * fovSafeRegion;

            let lookAt:THREE.Vector3 = FrameHelper.getFramingTarget(fovX, fovY, headHeightRatio,
                targetPositions, currentDirection, currentOrigin, cameraPosInFaceXY[0], cameraPosInFaceXY[1]);

            if(lookAt){
                FaceFinder.log.debug("FaceFinder.getCenterFromTargets() generated look-at target "+JSON.stringify(lookAt)
                    +" from face locations "+JSON.stringify(targetPositions)
                    +" using tracking camera "+cameraTracking+", photo camera "+cameraPhoto+","
                    +" headHeightRatio "+headHeightRatio+", fovSafeRegion "+fovSafeRegion+","
                    +" current position "+JSON.stringify(currentOrigin)+", direction "+JSON.stringify(currentDirection)+","
                    +" and camera data "+JSON.stringify(jibo.lps.motionData.cameras));
            }
            return lookAt;
        }
        catch(err){
            FaceFinder.log.warn('FaceFinder.getCenterFromTargets() Got error computing lookat:'+err);
            return null;
        }
    }

    /**
     * Get array of targets using LPS motion data.
     * @param {any} motionData - LPS motion data
     * @param {boolean} [includeFaceDetects = true] - flag determining if face detects should be included
     * @param {number} [includeFaceDetects = 0] - flag determining if face detects should be included
     * @return {THREE.Vector3[]} - carray of targets
     */
    public getTargetsFromMotionData(motionData:any, includeFaceDetects:boolean = true, requiredConfidence:number = 0):THREE.Vector3[] {
        let targetPositions:THREE.Vector3[] = [];
        // check for people within entities
        if(motionData.entities && motionData.entities.length){
            let inFOV:boolean;
            let part:any;
            for(let entity of motionData.entities) {
                //NOTE :: Simulator does not sufficiently mimic real LPS
                if(entity.description === 'person'){
                    // check if tracked person is in field of views
                    // NOTE :: do we need to check FoV, is it accurate?
                    inFOV = true;
                    if (entity.parts.length > 0) {
                        // NOTE :: the first part should be the face
                        part = entity.parts[0];
                        if (part.value.trackers.length > requiredConfidence) {
                            inFOV = part.value.trackers[0].inFOV;
                        }
                    }

                    if (inFOV && entity.confidence >= 0) {
                        targetPositions.push(new THREE.Vector3().copy(entity.position));
                    }
                }
            }
            FaceFinder.log.debug('FaceFinder.getBestTargets() found '+targetPositions.length+' valid faces out of '+motionData.entities.length+' faces from current LPS');
        }

        // check for faces within detections
        if(includeFaceDetects){
            if(motionData.detections && motionData.detections.length){
                for(let detection of motionData.detections){
                    //NOTE :: Simulator does not sufficiently mimic real LPS
                    if(detection.kind === 'face'){

                        if(detection.confidence >= requiredConfidence) {
                            targetPositions.push(new THREE.Vector3().copy(detection.position));
                        }
                    }
                }
            }
        }

        return targetPositions;
    }

    /**
     * NOT IN USE
     * Get the current position
     *
     */
    get screenLookAt():THREE.Vector3{
      const features = jibo.expression.features;
      const screenInfo = features.head;
      const screenPosition:THREE.Vector3 = screenInfo.position;
      const screenDirection:THREE.Vector3 = screenInfo.direction;
      const lookAt:THREE.Vector3 = screenDirection
          .clone()
          .normalize()
          .add(screenPosition);
      return lookAt;
    }

}

// This is the data provided for each detected face.
interface Detail {
  timestamp:[number, number];
  camera_id:number;
  entity_id:number;
  kind:'face';

  // Location within the source rect of the deteced face.
  location:Rect;

  //The source rect is the area in which the face can be seen in pixels.
  //This is so we know where in the camera's fov the chipDetails.rect is.
  source_rect:Rect;

  // 3D ray from camera to face is origin and direction
  ray_origin:Vec3;
  // Unit vector
  ray_dir:Vec3;
  // Range can be 0 if not known, else it is a range in meters.
  range:number;
  identity:Identity[];
  tags:Tag[];
}

interface Details {
  details:Detail[];
}

interface Rect {
    left:number;
    top:number;
    right:number;
    bottom:number;
}

interface Vec3 {
  x:number;
  y:number;
  z:number;
}

interface Identity {
  name:string;
  kind:string;
  confidence:number;
}

interface TagValue {
  // Timestamp of the value.
  ts:[number, number];
  confidence: number;
  // tag value is int, float, bool or string.
  tag: number | string | boolean;
}

interface Tag {
  key:string;
  value:TagValue;
}

module.exports = FaceFinder;
