import {BeSkill} from '@be/be-framework';

// analytics class for Tutorial skill
export default class Analytics {
    private _skill:BeSkill;
    private _launchSource:string;
    private _eventHeader:string = 'BB ';

    constructor(skill:BeSkill) {
        this._skill = skill;
    }

    public reset(launchSource:'from_fc'|'menu'|'speech'):void {
      this._launchSource = launchSource
    }

    public started():void {
        this._skill.track(
            this._eventHeader + 'Started',
            {
                launch_source:this._launchSource
            });
    }

    public completed(didComplete:boolean):void {
        this._skill.track(
            this._eventHeader + 'Completed',
            {
                launch_source:this._launchSource,
                completed:didComplete
            });
    }

    public stepComplete(event:string, didComplete:boolean|string, failedFirst:boolean|string):void {
        this._skill.track(
            this._eventHeader + event,
            {
                launch_source:this._launchSource,
                completed:didComplete,
                attempt:this.getAttempt(this.makeBoolean(didComplete), this.makeBoolean(failedFirst))
            }
        );
    }

    public responseComplete( didComplete:boolean = false, liked:boolean = false):void {
        this._skill.track(
            this._eventHeader + 'Response Step',
            {
                launch_source:this._launchSource,
                completed:didComplete,
                liked_dance:liked
            }
        );
    }

    public photoQuestionComplete( didComplete:boolean = false, saved:boolean = true):void {
        this._skill.track(
            this._eventHeader + 'Photo Question Step',
            {
                launch_source:this._launchSource,
                completed:didComplete,
                saved_photo:saved
            }
        );
    }

    public choseEnrollment(didComplete:boolean = false, choseEnroll:boolean = false):void {
        this._skill.track(
            this._eventHeader + 'Chose Enrollment',
            {
                completed:didComplete,
                chose_to_enroll:choseEnroll
            }
        );
    }

    private getAttempt(didComplete:boolean, failedFirst:boolean):'first'|'second'|'na' {
      if(didComplete){
          return (failedFirst) ? 'second' : 'first';
      }
      else{
          return 'na';
      }
    }

    private makeBoolean(value:boolean|string):boolean {
        if(typeof value === 'string'){
            return (value === 'true');
        }
        else{
            return value;
        }
    }
}
