/// <reference path="../../typings/index.d.ts" />
import jibo = require('jibo');
import animate = require('pixi-animate');

/**
* View class created to test use of custom transitions
* @class PhotoView
* @extends module:jibo/face.View
*/
class CameraView extends jibo.rendering.gui.views.View
{
    public static log = null;
    /**
    * The default class identifier.
    * Generally used to register the class.
    * @name module:jibo/face.TransMenu#DEFAULT_TYPE
    * @type {String}
    * @private
    * @readOnly
    */
    public static get DEFAULT_TYPE():string {return 'CameraView';}

    private _cameraClip:jibo.rendering.gui.components.Clip;

    private _body:animate.MovieClip;
    private _light:animate.MovieClip;
    private _ring:animate.MovieClip;
    private _lens:animate.MovieClip;
    private _lensRing:animate.MovieClip;
    private _iris:animate.MovieClip;
    private _corners:animate.MovieClip;

    private _bodyScale:number;
    private _lensScale:number;
    private _irisScale:number;
    private _lensPosition:PIXI.Point;
    private _bodyPosition:PIXI.Point;
    private _lensZoomed:boolean = false;
    private _timer:jibo.utils.DelayedCall;

    private static MAX_RADIUS_X:number = 120;
    private static MAX_RADIUS_Y:number = 60;
    private static MIN_DURATION:number = 200;
    private static MAX_DURATION:number = 1200;
    private static MAX_ROTATION:number = Math.PI/2;
    private static MAX_LENS_SCALE:number = 1.4;
    private static MAX_IRIS_SCALE:number = 1.6;

    /**
    * The Class type variant.
    * The MenuButton allows for type variants within it.
    * @overrides
    * @name module:jibo/face.TransMenu#_type
    * @type {String}
    * @protectedjibo sim /
    */
    protected _type:string = CameraView.DEFAULT_TYPE;

    //////////////////////// CONSTRUCTION ////////////////////////

    /**
     * Construct View
     */
    constructor () {
        super();
        // have custom eye transitions happen in all cases of transition to or from EyeView
        this.id = 'cameraView';
        this.transitionStageOnly = true;
        this.closeOnSwipeDown = false;
        (<any>this)._category = jibo.face.views.CATEGORY.DISPLAY;

        this.addTransition(jibo.rendering.gui.views.EyeView.DEFAULT_TYPE, true, this.openFromEye, jibo.face.views.TRANSITION.NONE);
        this.lensSearch = this.lensSearch.bind(this);
        this.startLensSearch = this.startLensSearch.bind(this);
    }

    public ready():void {

        // set camera timeline to opened frame
        this._cameraClip.movieClip.gotoAndStop('open_stop');

        // save references to Graphics within timeline
        let clip:PIXI.animate.MovieClip = this._cameraClip.movieClip;
        this._corners = clip['corners'];
        this._ring = clip['ring'];
        this._body = clip['body'];
        this._light = this._body['light'];
        this._lens = clip['lens'];
        this._lensRing = this._lens['lensCase']['ring'];
        this._iris = this._lens['lensFront']['iris'];

        // set up sub-movieclips
        this._body.gotoAndStop('open_stop');
        this._lens.gotoAndStop('open_stop');
        this._ring.gotoAndStop('open_stop');
        this.setLight('black');

        // make sure everything has correct visibility
        clip.visible = true;
        clip.alpha = 1;
        this._ring.visible = false;
        this._ring.alpha = 1;
        this._body.visible = true;
        this._body.alpha = 1;
        this._lens.visible = true;
        this._lens.alpha = 1;

        // hide corners, will use later
        this._corners.visible = false;
        this._corners.alpha = 1;

        super.ready();
    }

    public applyData():void {
        // load sfx
        this.addAssetDescriptorObject(
            {
                id: 'camera-sfx',
                type: 'sound',
                src: 'audio/camera-open.m4a'
            }
        );
        // create camera clip component
        this._cameraClip = new jibo.rendering.gui.components.Clip();
        this._cameraClip.addAssetDescriptorObject(
            {
                id: 'camera',
                type: 'timeline',
                src: 'assets/camera/camera.js',
                upload: true
            }
        );
        //this._cameraClip.setTargetPosition(jibo.rendering.FaceRenderer.WIDTH/2, jibo.rendering.FaceRenderer.HEIGHT/2);
        this.addComponent(this._cameraClip, 'cameraClip');

        super.applyData();
    }

    /**
     * Custom transition for opening from an EyeView.
     * @method jibo.face.MenuView#openFromEye
     * @param {Function} callback - Callback fired when close is complete.
     * @intdocs
     */
    public openFromEye(callback:Function):void {

        this._cameraClip.display.visible = false;

        // add eye to View's stage and center
        const eye:jibo.rendering.eye.EyeContainer = jibo.face.eye;
        this._stage.addChild(eye);
        eye.active = false;
        eye.visible = true;

        // create tweens to overshoot eye scale target - 550 == ViewManager.TRANS_TIME
        const duration:number = 550 * .7;
        super.transitionFadeOutTo(
            () => {
                //reset eye values & remove eye from stage
                this._stage.removeChild(eye);
                eye.active = false;

                // play sound, have to unlock input, should allow override in actionHandler
                let action:jibo.rendering.gui.actions.ActionData = new jibo.rendering.gui.actions.ActionData('sound', {id:'camera-sfx'});
                this._inputLocked = false;
                super.actionHandler(action);
                this._inputLocked = true;

                // play camera animation
                this._ring.visible = true;
                PIXI.animate.Animator.play(this._body, 'open');
                PIXI.animate.Animator.play(this._lens, 'open');
                PIXI.animate.Animator.play(this._ring, 'open');
                this._cameraClip.display.visible = true;
                // don't need to wait for animation to finish open to proceed
                callback();
            },
            1.1,
            .8,
            .6,
            duration
        );
    }

    public destroy():void{
        // stop timer
        this._lensZoomed = false;
        if(this._timer){
            this._timer.destroy();
            this._timer = null;
        }

        // stop all tweens
        if(this._body){
            jibo.rendering.tween.TweenManager.stop(this._body);
            this._body = null;
        }
        if(this._lens){
            jibo.rendering.tween.TweenManager.stop(this._lens);
            this._lens = null;
        }
        if(this._lensRing){
            jibo.rendering.tween.TweenManager.stop(this._lensRing);
            this._lensRing = null;
        }
        if(this._iris){
            jibo.rendering.tween.TweenManager.stop(this._iris);
            this._iris = null;
        }
        if(this._corners){
            jibo.rendering.tween.TweenManager.stop(this._corners);
            this._corners = null;
        }
        // manually clean up pointers
        this._cameraClip = null;
        this._light = null;
        this._ring = null;
        this._corners = null;
        this._lensPosition = null;
        this._bodyPosition = null;

        super.destroy();
    }

    /**
    * Keep reference to the standard display values before prior ot any transformation
    */
    public storeDefaultValues():void{
        // store scale values
        this._lensScale = this._lens.scale.x;
        this._bodyScale = this._body.scale.x;
        this._irisScale = this._iris.scale.x;
        this._lensPosition = new PIXI.Point(this._lens.x, this._lens.y);
        this._bodyPosition = new PIXI.Point(this._body.x, this._body.y);
        this._ring.visible = false;
    }

    /**
    * Change camera view to expand camera lens and shrink & hide camera body.
    */
    public expandToLens(callback?:Function, duration:number = 600):void {
        this._lensZoomed = true;
        this.setLight('red');
        // get center
        let centerX:number = jibo.face.width * .5;
        let centerY:number = jibo.face.height * .55;

        // shrink camera body
        const bodyScale:number = this._bodyScale * .96;
        jibo.rendering.tween.TweenManager.stop(this._body);
        jibo.rendering.tween.TweenManager.play(
            this._body,
            {
                to: {
                    'scale.x': bodyScale,
                    'scale.y': bodyScale,
                },
                duration: duration,
                ease: 'backOut'
            }
        );
        // scale up lens
        const lensScale:number = this._lensScale * CameraView.MAX_LENS_SCALE;
        jibo.rendering.tween.TweenManager.stop(this._lens);
        jibo.rendering.tween.TweenManager.play(
            this._lens,
            {
                to: {
                    'scale.x': lensScale,
                    'scale.y': lensScale,
                    'x': centerX,
                    'y': centerY
                },
                duration: duration,
                ease: 'backOut'
            },
            () => {
                this.startLensSearch();
                if(callback){
                    callback();
                }
            }
        );
        // scale up iris
        const irisScale:number = this._irisScale * CameraView.MAX_IRIS_SCALE;
        jibo.rendering.tween.TweenManager.stop(this._iris);
        jibo.rendering.tween.TweenManager.play(
            this._iris,
            {
                to: {
                    'scale.x': irisScale,
                    'scale.y': irisScale
                },
                duration: duration,
                ease: 'backOut'
            }
        );
        jibo.rendering.tween.TweenManager.stop(this._lensRing);
        jibo.rendering.tween.TweenManager.play(
            this._lensRing,
            {
                to: {
                    rotation: Math.PI/4
                },
                duration: duration,
                ease: 'backOut'
            }
        );
    }

    public shrinkLens(callback?:Function, duration:number = 500):void {
        // revert to camera if in lens mode (body would be invisible if this is the case)
        if(this._lensZoomed){
            this.registerUpdate(false);
            this._lensZoomed = false;
            // destroy timer
            if(this._timer){
                this._timer.destroy();
                this._timer = null;
            }
            // resize body to nornal scale
            jibo.rendering.tween.TweenManager.stop(this._body);
            jibo.rendering.tween.TweenManager.play(
                this._body,
                {
                    to: {
                        'scale.x': this._bodyScale,
                        'scale.y': this._bodyScale,
                        'x': this._lensPosition.x,
                        'y': this._lensPosition.y
                    },
                    duration: duration,
                    ease: 'backIn'
                }
            );
            // resize lens
            jibo.rendering.tween.TweenManager.stop(this._lens);
            jibo.rendering.tween.TweenManager.play(
                this._lens,
                {
                    to: {
                        'scale.x': this._lensScale,
                        'scale.y': this._lensScale,
                        'x': this._lensPosition.x,
                        'y': this._lensPosition.y
                    },
                    duration: duration,
                    ease: 'backIn'
                },
                callback
            );
            jibo.rendering.tween.TweenManager.stop(this._iris);
            jibo.rendering.tween.TweenManager.play(
                this._iris,
                {
                    to: {
                        'scale.x': this._irisScale,
                        'scale.y': this._irisScale
                    },
                    duration: duration,
                    ease: 'backIn'
                }
            );
            jibo.rendering.tween.TweenManager.stop(this._lensRing);
            jibo.rendering.tween.TweenManager.play(
                this._lensRing,
                {
                    to: {
                        rotation: 0
                    },
                    duration: duration,
                    ease: 'backIn'
                }
            );
        }
    }

    public showCorners(callback?:Function):void {
        // set light to green
        this.setLight('green');

        // set corners
        this._corners.visible = true;
        this._corners.alpha = 0;
        const cornerDuration:number = 300;

        // tween corners to be visible & in frame
        jibo.rendering.tween.TweenManager.play(
            this._corners,
            {
                to: {
                    'scale.x': 1,
                    'scale.y': 1,
                },
                from: {
                    'scale.x': 1.2,
                    'scale.y': 1.2,
                },
                duration: cornerDuration,
                ease: 'backOut'
            }
        );
        jibo.rendering.tween.TweenManager.play(
            this._corners,
            {
                to: {
                    'alpha': 1,
                },
                duration: cornerDuration,
                ease: 'sineOut'
            },
            callback
        );
    }

    public hideCorners(callback?:Function):void {
        // hide corners if they are visible
        if(this._corners.visible){
            let cornerDuration:number = 300;
            // show corners
            jibo.rendering.tween.TweenManager.play(
                this._corners,
                {
                    to: {
                        'scale.x': 1.2,
                        'scale.y': 1.2,
                    },
                    duration: cornerDuration,
                    ease: 'backIn'
                },
                () => {
                    this._corners.visible = false;
                }
            );
            jibo.rendering.tween.TweenManager.play(
                this._corners,
                {
                    to: {
                        'alpha': 0,
                    },
                    duration: cornerDuration,
                    ease: 'sineOut'
                },
                callback
            );
        }
        else if(callback){
            callback();
        }
    }

    public setLight(color:'red'|'green'|'black'):void {
        if(this._light){
            switch(color) {
                case 'red':{}
                case 'green':{}
                case 'black':{
                    this._light.gotoAndStop(color);
                    break;
                }
                default: {
                    // invalid input
                    this._light.gotoAndStop('black');
                }
            }
        }
    }

    private startLensSearch():void{
        // move lens to random position on interval
        const lapse:number = 500 + Math.random() * 400;
        // set a timeout
        if(this._timer){
            this._timer.destroy();
        }
        this._timer = jibo.timer.setTimeout(
            this.lensSearch,
            lapse
        )
    }

    private lensSearch():void{
        if(this._lensZoomed){
            // choose random position in circle, use square root to achieve even distribution
            let centerX:number = jibo.face.width * .5;
            let centerY:number = jibo.face.height * .5;
            let seed:number = Math.sqrt(Math.random());
            let radians:number = 2 * Math.PI * Math.random();
            let targetX:number = centerX + seed * CameraView.MAX_RADIUS_X * Math.cos(radians);
            let targetY:number = centerY + seed * CameraView.MAX_RADIUS_Y * Math.sin(radians);
            // distance from current position to next position
            let moveDistance:number = Math.abs(this.getDistance(this._lens.x, this._lens.y, targetX, targetY));
            // distance from center position to next position
            let centerDistance:number = Math.abs(this.getDistance(centerX, centerY, targetX, targetY))
            // duration of movement based on distance between current position and target
            let duration:number = CameraView.MIN_DURATION + CameraView.MAX_DURATION * (moveDistance/(CameraView.MAX_RADIUS_X * 2));

            let distanceDelta:number = centerDistance/CameraView.MAX_RADIUS_X;
            let lensScale:number = this._lensScale * (CameraView.MAX_LENS_SCALE - distanceDelta * .2);
            let irisScale:number = this._irisScale * (CameraView.MAX_IRIS_SCALE - distanceDelta * .4);
            let rotationDelta:number = lensScale - this._lens.scale.x;
            let rotation:number = rotationDelta * CameraView.MAX_ROTATION;

            // tween to new target
            jibo.rendering.tween.TweenManager.stop(this._lens);
            jibo.rendering.tween.TweenManager.play(
                this._lens,
                {
                    to: {
                        'scale.x': lensScale,
                        'scale.y': lensScale,
                        x: targetX,
                        y: targetY
                    },
                    duration: duration,
                    ease: 'backInOut'
                },
                this.startLensSearch
            );
            jibo.rendering.tween.TweenManager.stop(this._body);
            jibo.rendering.tween.TweenManager.play(
                this._body,
                {
                    to: {
                        x: targetX,
                        y: targetY
                    },
                    duration: duration,
                    ease: 'backInOut'
                }
            );
            jibo.rendering.tween.TweenManager.stop(this._iris);
            jibo.rendering.tween.TweenManager.play(
                this._iris,
                {
                    to: {
                        'scale.x': irisScale,
                        'scale.y': irisScale
                    },
                    duration: duration,
                    ease: 'backInOut'
                }
            );
            jibo.rendering.tween.TweenManager.stop(this._lensRing);
            jibo.rendering.tween.TweenManager.play(
                this._lensRing,
                {
                    to: {
                        rotation: rotation
                    },
                    duration: duration,
                    ease: 'backInOut'
                }
            );
        }
    }

    private getDistance(x1:number, y1:number, x2:number, y2:number):number {
        return Math.sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
    }

}

export default CameraView;
